# -*- coding: utf-8 -*-
from __future__ import annotations

# Bilingual manual chapters data (HTML blocks)
MANUAL_CHAPTERS: dict[str, str] = {'1-1': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📖 1.1 Démarrage rapide</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Menu Principal > Alt + ?</span></p>\n            <p>Bienvenue dans FABOuanes. Ce guide de 54 chapitres est conçu pour vous aider à maîtriser l\'application.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📖 1.1 البدء السريع</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">القائمة الرئيسية > Alt + ?</span></p>\n            <p>مرحبًا بكم في دليل فاب وناس. تم تصميم هذا الدليل المكون من 54 فصلاً لمساعدتك في فهم التطبيق.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><strong>[Excel] ➔ [FABOuanes] ➔ [Bons PDF]</strong></div>\n          </div>', '1-2': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🔐 1.2 Connexion & Session</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Adresse URL racine (/) de l\'application</span></p>\n            <p>Authentification sécurisée via login.html. La session expire après inactivité pour préserver la sécurité de vos comptes.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🔐 1.2 الدخول والجلسة</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الرابط الرئيسي (/) للتطبيق</span></p>\n            <p>تسجيل الدخول الآمن عبر login.html. تنتهي الجلسة تلقائيًا بعد فترة من الخمول لحماية حساباتك.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><input class="form-control form-control-sm mb-1" placeholder="Nom d\'utilisateur" value="admin" disabled><button class="btn btn-dark btn-sm py-0 w-100">Connexion</button></div>\n          </div>', '1-3': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📲 1.3 QR Code Mobile Link</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Menu Profil > Connexion Mobile</span></p>\n            <p>Couplage mobile instantané en scannant le QR code dynamique temporaire (valide 2 minutes) pour connecter votre smartphone.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📲 1.3 رابط الهاتف رمز QR</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">قائمة الحساب > الاتصال بالهاتف</span></p>\n            <p>اقتران سريع بالهاتف بمسح رمز QR الديناميكي المؤقت (صالح لمدة دقيقتين) لتوصيل هاتفك الذكي.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><i class="bi bi-qr-code" style="font-size:2rem;"></i><br><small class="text-success">Jeton actif</small></div>\n          </div>', '1-4': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🎨 1.4 Personnalisation</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Menu Profil > Paramètres de thème</span></p>\n            <p>Ajustez le thème visuel (Clair/Sombre), la police et la disposition de la barre latérale pour votre confort visuel.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🎨 1.4 تخصيص الواجهة</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">قائمة الحساب > إعدادات المظهر</span></p>\n            <p>اضبط المظهر البصري (فاتح/مظلم)، وحجم الخط وتنسيق القائمة الجانبية لراحة عينيك.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><button class="btn btn-outline-dark btn-sm py-0">Thème Sombre</button></div>\n          </div>', '1-5': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🔑 1.5 Changement Mot de Passe</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Menu Profil > Sécurité et Profil</span></p>\n            <p>Mettez régulièrement à jour votre mot de passe utilisateur pour prévenir tout accès frauduleux à vos comptes d\'entreprises.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🔑 1.5 تغيير كلمة المرور</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">قائمة الحساب > الأمان والحساب</span></p>\n            <p>قم بتحديث كلمة المرور بشكل دوري لمنع أي دخول غير مصرح به لحسابات شركتك.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><input type="password" class="form-control form-control-sm" value="••••••••" disabled></div>\n          </div>', '1-6': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🍪 1.6 Cookies & Sécurité</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Automatique / Paramètres Navigateur</span></p>\n            <p>Les cookies chiffrés protègent la session et bloquent les attaques CSRF (Cross-Site Request Forgery) lors des transferts.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🍪 1.6 ملفات الارتباط والأمان</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">تلقائي / إعدادات المتصفح</span></p>\n            <p>تحمي ملفات تعريف الارتباط المشفرة الجلسة وتمنع ثغرات CSRF أثناء إرسال البيانات.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-success-subtle text-success-emphasis text-center"><strong>Session Sécurisée (SSL/HTTPS)</strong></div>\n          </div>', '2-1': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📊 2.1 Les KPIs Financiers</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Bandeau supérieur du Dashboard</span></p>\n            <p>Calcul en temps réel des ventes du jour, de l\'encaisse physique, du bénéfice estimé et des créances clients globales.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📊 2.1 المؤشرات المالية</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الشريط العلوي للوحة القيادة</span></p>\n            <p>حساب فوري لمبيعات اليوم، التحصيلات النقدية، الأرباح المتوقعة والديون المستحقة.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Ventes: <strong>150 000 DA</strong> | Créances: <strong class="text-danger">85 000 DA</strong></div>\n          </div>', '2-2': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📈 2.2 Graphiques & Analyse</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Section centrale du Dashboard</span></p>\n            <p>Graphiques basés sur Chart.js pour visualiser les bénéfices bruts et nets par jour, mois ou exercice comptable complet.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📈 2.2 الرسوم البيانية</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">القسم الأوسط للوحة القيادة</span></p>\n            <p>رسوم بيانية مدعومة بـ Chart.js لمعاينة الأرباح الإجمالية والصافية حسب اليوم، الشهر أو السنة الحسابية.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><i class="bi bi-graph-up text-primary" style="font-size:2rem;"></i></div>\n          </div>', '2-3': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>💬 2.3 Sabrina (Assistante IA)</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Bandeau latéral droit (Dashboard)</span></p>\n            <p>Sabrina traite les questions en langage naturel et exige une double validation interactive pour toute écriture comptable.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">💬 2.3 سابرينا (المساعد الذكي)</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">اللوحة الجانبية اليمنى (لوحة القيادة)</span></p>\n            <p>تجيب سابرينا على الأسئلة وتتطلب موافقة ثنائية تفاعلية قبل القيام بأي تعديل على الحسابات.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-warning-subtle text-warning-emphasis text-center">Valider action Sabrina ? <button class="btn btn-warning btn-sm py-0">Oui</button></div>\n          </div>', '2-4': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📜 2.4 Historique Sabrina</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Panneau Sabrina > Liste des fils de discussion</span></p>\n            <p>Gérez vos conversations distinctes avec Sabrina et renommez les fils de discussion pour organiser vos analyses.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📜 2.4 سجل المحادثات</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">لوحة سابرينا > قائمة المحادثات</span></p>\n            <p>أدر محادثاتك المنفصلة مع سابرينا وقم بتعديل عناوينها لتنظيم تحليلاتك المالية.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">💬 Analyse Stocks (10/07)</div>\n          </div>', '2-5': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📉 2.5 Analyse des Tendances</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Dashboard > Outils analytiques</span></p>\n            <p>Comparez les performances actuelles avec celles de la semaine passée (J-7) ou du mois précédent pour anticiper les baisses.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📉 2.5 تحليل الاتجاهات</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">لوحة القيادة > أدوات التحليل</span></p>\n            <p>قارن الأداء الحالي بأداء الأسبوع الماضي (J-7) أو الشهر السابق للتنبؤ بتقلبات السوق.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center text-success">↑ +12.4% vs J-7</div>\n          </div>', '2-6': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🔔 2.6 Notifications WebSocket</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Notifications de la barre supérieure (Badge clignotant)</span></p>\n            <p>Flux d\'alertes instantanées WebSocket en cas d\'ajustement de stock critique, de vente externe ou de sauvegarde terminée.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🔔 2.6 التنبيهات الفورية</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">تنبيهات الشريط العلوي (أيقونة تومض)</span></p>\n            <p>تنبيهات فورية عبر WebSocket عند وصول المخزون للحد الحرج أو إتمام النسخ الاحتياطي.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-danger-subtle text-danger-emphasis text-center">⚠️ Stock Critique: Son de Blé (0 Sac)</div>\n          </div>', '3-1': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>👥 3.1 Clients (CRUD complet)</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Barre supérieure > Contacts > Clients</span></p>\n            <p>Ajoutez, modifiez ou retirez vos fiches clients. La suppression est bloquée s\'il existe la moindre transaction liée.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">👥 3.1 العملاء (إدارة كاملة)</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الشريط العلوي > جهات الاتصال > العملاء</span></p>\n            <p>أضف، عدل أو احذف بطاقات العملاء. يتم حظر الحذف تلقائيًا إذا كانت هناك أي فواتير مسجلة لهم.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Lotfi | Solde: <span class="badge bg-danger">15 000 DA</span></div>\n          </div>', '3-2': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📥 3.2 Importateur Excel</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Contacts > Bouton Importer Excel</span></p>\n            <p>Importation en bloc de fiches de calcul avec pré-visualisation quadrillée type tableur Excel pour validation des colonnes.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📥 3.2 مستورد إكسل</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">جهات الاتصال > زر استيراد إكسل</span></p>\n            <p>استيراد جماعي لبيانات العملاء والديون من ملفات إكسل مع معاينة ورقة البيانات قبل الحفظ.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-1 bg-light text-center" style="font-size:0.6rem;">Table: Client A | Dette: 10 000</div>\n          </div>', '3-3': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>⏸️ 3.3 Barre de Progrès</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">S\'affiche pendant l\'importation de fichiers volumineux</span></p>\n            <p>Barre de chargement inspirée de Windows permettant de mettre en pause, suspendre ou suivre le rythme de stockage en base.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">⏸️ 3.3 شريط التقدم</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">يظهر أثناء استيراد الملفات الكبيرة</span></p>\n            <p>شريط تحميل تفاعلي يحاكي نقل ملفات ويندوز لمراقبة سرعة تخزين البيانات في النظام.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><div class="progress" style="height:8px;"><div class="progress-bar bg-success" style="width:75%;"></div></div><small>75% Terminé</small></div>\n          </div>', '3-4': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🏢 3.4 Fournisseurs & Soldes</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Contacts > Fournisseurs</span></p>\n            <p>Enregistrez vos fournisseurs partenaires pour suivre de manière isolée vos dettes d\'approvisionnement en matières premières.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🏢 3.4 الموردون والأرصدة</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">جهات الاتصال > الموردون</span></p>\n            <p>سجل بيانات الموردين لمتابعة ديون توريد المواد الأولية بشكل مستقل ودقيق.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Moulins d\'Alger | Dette: <span class="badge bg-danger">150 000 DA</span></div>\n          </div>', '3-5': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🧹 3.5 Doublons & Fusion</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Contacts > Doublons & Fusion</span></p>\n            <p>Identifiez les fiches clients dupliquées et fusionnez leur historique financier sans altérer le montant cumulé de leur solde.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🧹 3.5 تكرار الحسابات ودمجها</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">جهات الاتصال > دمج الحسابات المتكررة</span></p>\n            <p>ابحث عن حسابات العملاء المتكررة وادمج تاريخ معاملاتهم المالية دون التأثير على أرصدتهم المتراكمة.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><button class="btn btn-dark btn-sm py-0">Fusionner Doublons</button></div>\n          </div>', '3-6': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📤 3.6 Exportation Contacts</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Contacts > Exporter la liste des clients</span></p>\n            <p>Téléchargez la liste complète de vos clients avec leurs numéros de téléphone et leurs soldes débiteurs en format Excel.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📤 3.6 تصدير جهات الاتصال</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">جهات الاتصال > تصدير قائمة العملاء</span></p>\n            <p>حمل القائمة الكاملة لزبائنك مع أرقام هواتفهم وأرصدة ديونهم في ملف إكسل بضغطة زر.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><i class="bi bi-file-earmark-excel text-success" style="font-size:1.5rem;"></i></div>\n          </div>', '4-1': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🛒 4.1 Ventes & Versements</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Opérations > Nouvelle Vente</span></p>\n            <p>Enregistrez vos ventes et déduisez automatiquement les versements du solde global accumulé de la fiche du client.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🛒 4.1 المبيعات والمدفوعات</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">العمليات > بيع جديد</span></p>\n            <p>سجل المبيعات والمدفوعات. يقوم النظام بخصم المبالغ المقبوضة من الدين الإجمالي للزبون فورًا.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Vente: 10 000 DA | Reçu: 8 000 DA</div>\n          </div>', '4-2': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📦 4.2 Achats & Fournisseurs</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Opérations > Nouvel Achat</span></p>\n            <p>Enregistrez les entrées en stock de matières premières et recalculez automatiquement le PAMP (Prix d\'Achat Moyen Pondéré).</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📦 4.2 المشتريات والموردون</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">العمليات > شراء جديد</span></p>\n            <p>سجل وصول السلع والمواد الأولية المخزنية ليقوم النظام بإعادة حساب متوسط سعر الشراء تلقائيًا.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Orge: <strong>+100 Sacs</strong></div>\n          </div>', '4-3': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🗑️ 4.3 Édition & Annulations</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Opérations > Sélectionner transaction > Supprimer</span></p>\n            <p>La suppression d\'un bon de vente ou de règlement antérieur recalcule dynamiquement en cascade tous les soldes ultérieurs.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🗑️ 4.3 التعديل والإلغاء</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">العمليات > حدد المعاملة > حذف</span></p>\n            <p>حذف أي وصل بيع أو تحصيل سابق يقوم بإعادة حساب تسلسلية لكافة الأرصدة اللاحقة لضمان دقة الديون.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-danger-subtle text-danger text-center">⚠️ Alerte recalcul en cascade</div>\n          </div>', '4-4': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📄 4.4 États de compte client</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Clients > Fiche client > Extrait de compte</span></p>\n            <p>Générez un relevé détaillé de tous les bons de livraison et des encaissements sur une période pour justifier du solde dû.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📄 4.4 كشوف الحسابات</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">العملاء > بطاقة العميل > كشف الحساب</span></p>\n            <p>استخرج كشف حساب تفصيلي لجميع المبيعات والمدفوعات لإثبات رصيد الدين المتبقي للزبون.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><small>01/07: Vente +15k | 05/07: Recette -10k</small></div>\n          </div>', '4-5': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>💵 4.5 Gestion des Acomptes</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Opérations > Enregistrer un versement (Sélectionner Acompte)</span></p>\n            <p>Enregistrez les avances de vos clients pour réserver des matières premières ou préparer des lots industriels d\'aliments.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">💵 4.5 العربون والتسبيقات</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">العمليات > تسجيل دفعة مالية (عربون)</span></p>\n            <p>سجل دفعات العربون والتسبيقات المالية لحجز المواد الأولية للزبائن قبل تسليم البضاعة.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Avance Client: <span class="badge bg-success">50 000 DA</span></div>\n          </div>', '4-6': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📜 4.6 Historique Global</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Barre supérieure > Opérations (Onglet Historique)</span></p>\n            <p>Journal complet de toutes vos transactions. Vous pouvez filtrer par type (Ventes, Achats, Versements, Dépenses).</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📜 4.6 سجل العمليات العام</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الشريط العلوي > العمليات > سجل المعاملات</span></p>\n            <p>السجل الموحد لجميع العمليات. يمكنك التصفية حسب النوع (مبيعات، مشتريات، مدفوعات، مصاريف).</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">🔍 Rechercher transaction...</div>\n          </div>', '5-1': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📋 5.1 Fiches Recettes</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Barre supérieure > Production > Fiches Recettes</span></p>\n            <p>Définissez la composition (formule de fabrication) d\'un aliment fini à partir de vos matières premières en stock.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📋 5.1 البطاقات الفنية والوصفات</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الشريط العلوي > الإنتاج > بطاقات الوصفات</span></p>\n            <p>حدد تركيبة الخلطة العلفية (الصيغة الفنية) لإنتاج علف جاهز بناءً على المواد المتوفرة.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><small>Orge (60%) + نخالة (40%)</small></div>\n          </div>', '5-2': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🏭 5.2 Lancement de Production</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Barre supérieure > Production > Lancer</span></p>\n            <p>Lancez l\'ordre de production pour déduire automatiquement les ingrédients du stock et ajouter les sacs finis.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🏭 5.2 إطلاق الإنتاج</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الشريط العلوي > الإنتاج > إطلاق إنتاج</span></p>\n            <p>أطلق أمر التصنيع ليقوم النظام بخصم المكونات وإضافة كمية الأكياس العلفية الجاهزة للمستودع.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><button class="btn btn-success btn-sm py-0 w-100">Lancer Production</button></div>\n          </div>', '5-3': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📦 5.3 Suivi des Stocks Alerte</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Automatique (Dashboard et Catalogue)</span></p>\n            <p>Alerte visuelle rouge WebSocket dès qu\'une matière première descend sous le seuil d\'alerte configuré pour éviter l\'arrêt de l\'usine.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📦 5.3 المخزون والتنبيهات</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">تلقائي (لوحة القيادة ودليل السلع)</span></p>\n            <p>تنبيه أحمر فوري على الشاشة عند انخفاض كمية أي مادة في المستودع لتفادي توقف المصنع.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-danger-subtle text-danger text-center">⚠️ Stock Critique: Orge (120kg)</div>\n          </div>', '5-4': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📜 5.4 Historique Production</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Production > Historique de fabrication</span></p>\n            <p>Retrouvez l\'historique complet de tous les ordres de fabrication validés et suivez le rendement de votre usine.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📜 5.4 سجل الإنتاج</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الإنتاج > سجل عمليات التصنيع</span></p>\n            <p>تصفح السجل الكامل لجميع أوامر التصنيع السابقة وتتبع مردودية الآلات والمصنع.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><small>10/07: +120 Sacs Aliment Mouton</small></div>\n          </div>', '5-5': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🍂 5.5 Perte Matières Premières</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Production > Enregistrer une perte</span></p>\n            <p>Enregistrez le taux d\'humidité, la poussière ou les sacs endommagés pour corriger l\'état du stock physique disponible.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🍂 5.5 ضياع وتلف المواد</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الإنتاج > تسجيل ضياع المواد</span></p>\n            <p>سجل نسب الرطوبة، الأكياس التالفة أو الضياع لتعديل كميات المخزون الفعلي المتبقي.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Perte enregistrée: <span class="badge bg-danger">25 kg Son de Blé</span></div>\n          </div>', '5-6': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🧮 5.6 Calcul Coût de Revient</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Production > Fiche Recette > Analyse de revient</span></p>\n            <p>Calculez automatiquement le coût de fabrication d\'un sac d\'aliment fini à partir du prix moyen pondéré de chaque composant.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🧮 5.6 تكلفة الإنتاج الإجمالية</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الإنتاج > بطاقة الوصفة > تكلفة الإنتاج</span></p>\n            <p>احسب التكلفة الإجمالية لإنتاج كيس علف واحد بناءً على أسعار شراء المكونات من الموردين.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Coût sac: <strong>1 100 DA</strong> | Marge brute: <strong>300 DA</strong></div>\n          </div>', '6-1': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>💸 6.1 Dépenses Annexes</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Outils > Dépenses</span></p>\n            <p>Enregistrez tous les frais (Sonelgaz, essence, salaires) pour qu\'ils soient déduits de vos bénéfices bruts journaliers.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">💸 6.1 المصاريف الملحقة</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الأدوات > المصاريف</span></p>\n            <p>سجل كافة المصاريف العامة (كهرباء، وقود، أجور) ليتم خصمها تلقائيًا من الأرباح الإجمالية.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Facture Sonelgaz: <span class="badge bg-danger">14 500 DA</span></div>\n          </div>', '6-2': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📝 6.2 Bloc-Notes & Mémos</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Outils > Bloc-Notes</span></p>\n            <p>Mémos rapides et persistants conservés dans la base de données SQLite pour votre profil utilisateur.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📝 6.2 دفتر الملاحظات</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الأدوات > دفتر الملاحظات</span></p>\n            <p>مفكرة سريعة ودائمة محفوظة في قاعدة البيانات لكل مستخدم لتسجيل الملاحظات الهامة.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-warning-subtle text-warning-emphasis text-center">📌 Relancer Karim pour versement</div>\n          </div>', '6-3': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🗃️ 6.3 Catalogue d\'Articles</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Outils > Catalogue d\'Articles</span></p>\n            <p>Inventaire de toutes les matières premières et produits finis avec indicateur visuel de l\'état du stock.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🗃️ 6.3 دليل السلع والمنتجات</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الأدوات > دليل السلع</span></p>\n            <p>قائمة كاملة بالمواد الأولية والمنتجات النهائية مع مؤشر مرئي لمستوى توفرها في المخازن.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Aliment Mouton | Stock: 450 Sacs</div>\n          </div>', '6-4': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>💰 6.4 Ajustement des Tarifs</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Catalogue > Modifier prix</span></p>\n            <p>Mettez à jour vos prix de vente selon le cours du soja ou de l\'orge pour protéger votre marge commerciale brute.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">💰 6.4 تعديل الأسعار</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">دليل السلع > تعديل السعر</span></p>\n            <p>حدث أسعار بيع الأعلاف حسب تغير أسعار الصويا والشعير في السوق لحماية أرباحك.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Prix: 1400 DA (Marge: 30%)</div>\n          </div>', '6-5': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🔍 6.5 Recherche multicritères</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Barre supérieure de recherche globale (toutes les pages)</span></p>\n            <p>Recherchez un client, un bon de livraison ou un article du stock instantanément depuis n\'importe quel endroit de l\'application.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🔍 6.5 البحث المتقدم</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">شريط البحث العلوي الموحد (جميع الواجهات)</span></p>\n            <p>ابحث عن اسم زبون، رقم فلوكة بيع، أو سلعة في المخزن فورًا من أي واجهة في التطبيق.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><input class="form-control form-control-sm" placeholder="🔍 Rechercher client ou bon..." disabled></div>\n          </div>', '6-6': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🧮 6.6 Calculatrice Intégrée</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Navbar > Icône de calculatrice</span></p>\n            <p>Utilisez la calculatrice intégrée pour évaluer rapidement les montants de vos remises ou les totaux de chargement.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🧮 6.6 الحاسبة المدمجة</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الشريط العلوي > رمز الآلة الحاسبة</span></p>\n            <p>استخدم الآلة الحاسبة المدمجة لحساب الخصومات التجارية أو مجموع حمولة الزبون بسرعة دون مغادرة الواجهة.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center" style="font-family:monospace;">[ 120 * 1400 = 168 000 ]</div>\n          </div>', '7-1': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📂 7.1 Explorateur de Bons</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Outils > Espace Bons</span></p>\n            <p>Consultez, téléchargez ou réimprimez tous les documents administratifs générés (bons de livraison, factures) en PDF.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📂 7.1 مستعرض الوصولات</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الأدوات > مساحة الوصولات</span></p>\n            <p>تصفح، حمل أو أعد طباعة جميع الوثائق الإدارية الصادرة (وصل تسليم، فاتورة) بصيغة PDF.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">BL_2026_009.pdf <button class="btn btn-dark btn-sm py-0">Ouvrir</button></div>\n          </div>', '7-2': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🖨️ 7.2 Formats A4 & A5 PDF</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Options d\'impression avant validation</span></p>\n            <p>Ajustez le format : A4 pour les factures professionnelles et A5 pour les bons de caisse rapides et économiques.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🖨️ 7.2 طباعة A4 و A5 PDF</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">خيارات الطباعة قبل الحفظ</span></p>\n            <p>اختر الحجم المناسب: A4 للفواتير الرسمية الكبيرة، و A5 للوصولات السريعة والاقتصادية في الورق.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><small>Format A4 Standard | Format A5 Reçu</small></div>\n          </div>', '7-3': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📥 7.3 Exportation Excel / CSV</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Opérations > Bouton Exporter</span></p>\n            <p>Exportez vos transactions comptables vers Excel ou CSV pour simplifier la transmission des rapports financiers.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📥 7.3 تصدير إكسل و CSV</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">العمليات > زر التصدير</span></p>\n            <p>صّدر سجل المعاملات المالية إلى ملفات إكسل أو CSV لتسهيل نقل التقارير إلى المحاسب.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><button class="btn btn-dark btn-sm py-0">Export XLS</button></div>\n          </div>', '7-4': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🧾 7.4 Reçus thermiques & Tickets</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Options d\'impression du bon > Ticket 80mm</span></p>\n            <p>Impression directe sur imprimantes thermiques de caisse (format standard 80mm) pour des ventes directes rapides.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🧾 7.4 الوصولات الحرارية</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">خيارات طباعة الوصل > تذكرة 80 مم</span></p>\n            <p>طباعة مباشرة على الطابعات الحرارية (قياس 80 مم القياسي) لنقاط البيع السريعة.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center" style="font-family:monospace; font-size:0.6rem;">TOTAL: 1400 DA</div>\n          </div>', '7-5': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>✒️ 7.5 Entêtes & Logos</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Admin > Paramètres d\'impression</span></p>\n            <p>Personnalisez les coordonnées de votre entreprise et importez votre logo pour habiller vos factures et bons PDF.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">✒️ 7.5 ترويسة الوصول والشعار</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الإدارة > إعدادات الطباعة</span></p>\n            <p>خصص معلومات شركتك (الهاتف، العنوان) وأضف شعار المؤسسة ليظهر أعلى الفواتير والوصولات.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Logo EURL OUANES</div>\n          </div>', '7-6': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>✍️ 7.6 Signature & Cachet</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Admin > Paramètres d\'impression > Ajouter cachet</span></p>\n            <p>Importez votre signature numérisée pour qu\'elle s\'appose automatiquement en bas de vos factures au format PDF.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">✍️ 7.6 التوقيع والختم</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الإدارة > إعدادات الطباعة > إضافة ختم</span></p>\n            <p>أضف توقيعك وختم الشركة الممسوح ضوئيًا ليتم وضعه تلقائيًا أسفل الفواتير والوصولات الصادرة.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><i class="bi bi-pencil-fill text-muted"></i> [Cachet Validé]</div>\n          </div>', '8-1': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🛠️ 8.1 Configuration de l\'IA</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Admin > Paramètres de Sabrina</span></p>\n            <p>Configurez Sabrina avec les serveurs Cloud de Google Gemini (clé API) ou le serveur local hors-ligne Ollama.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🛠️ 8.1 إعدادات الذكاء الاصطناعي</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الإدارة > إعدادات سابرينا</span></p>\n            <p>اضبط محرك الذكاء المشغل لسابرينا بين سحابة Google Gemini أو خادم Ollama المحلي دون إنترنت.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Radio: Gemini Cloud (Checked)</div>\n          </div>', '8-2': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>💾 8.2 Maintenance & Backups</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Admin > Maintenance</span></p>\n            <p>Sauvegardez votre base de données SQLite manuellement ou téléchargez des sauvegardes à intervalle régulier.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">💾 8.2 الصيانة والنسخ الاحتياطي</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الإدارة > الصيانة</span></p>\n            <p>احفظ نسخة احتياطية من قاعدة البيانات يدويًا أو حمل النسخ المحفوظة بانتظام لحماية حساباتك.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><button class="btn btn-dark btn-sm py-0 w-100">Lancer Back-up</button></div>\n          </div>', '8-3': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🔑 8.3 Comptes & Droits</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Admin > Gestion des utilisateurs</span></p>\n            <p>Définissez les comptes d\'accès pour vos employés. Les vendeurs ont un accès limité à la saisie de caisse courante.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🔑 8.3 الحسابات والصلاحيات</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الإدارة > تسيير المستخدمين</span></p>\n            <p>أضف حسابات مخصصة لعمال الشركة مع تحديد الصلاحيات (حساب بائع محدود، حساب مدير كامل).</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Admin (Accès total) | Vendeur (Limité)</div>\n          </div>', '8-4': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🕵️ 8.4 Journal d\'Audit</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Admin > Journal d\'Audit</span></p>\n            <p>Le système enregistre chaque action des utilisateurs (suppressions, modifications de prix) pour garantir la traçabilité.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🕵️ 8.4 سجل الرقابة والأمان</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الإدارة > سجل النشاطات</span></p>\n            <p>يسجل النظام كل عملية يقوم بها العمال (حذف فواتير، تغيير أسعار) لضمان الشفافية والأمان.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center" style="font-size:0.6rem; color:red;">ADMIN: Supprimé Vente #89</div>\n          </div>', '8-5': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🪙 8.5 Configuration de Devise</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Admin > Paramètres généraux > Devise</span></p>\n            <p>Configurez le symbole monétaire (par défaut DA pour Dinar Algérien) et le format de séparation des milliers.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🪙 8.5 إعدادات العملة</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الإدارة > الإعدادات العامة > العملة</span></p>\n            <p>اضبط رمز العملة الافتراضي للبرنامج (د.ج / Dinar Algérien) وطريقة فصل الآلاف في الأرقام.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Devise: <strong>Dinar Algérien (DA)</strong></div>\n          </div>', '8-6': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>🔄 8.6 Réinitialisation de l\'App</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Admin > Maintenance > Réinitialisation complète</span></p>\n            <p>Purger toutes vos données de vente, d\'achat et de contacts pour démarrer un nouvel exercice comptable (avec confirmation).</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">🔄 8.6 إعادة تهيئة التطبيق</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الإدارة > الصيانة > إعادة تهيئة كاملة</span></p>\n            <p>مسح كافة عمليات البيع والشراء والعملاء لبدء سنة مالية جديدة (يتطلب كلمة مرور الإدارة للتأكيد).</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-danger-subtle text-danger text-center"><button class="btn btn-danger btn-sm py-0 w-100">Réinitialiser l\'App</button></div>\n          </div>', '9-1': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>❓ 9.1 FAQ / Dépannage</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Menu Principal > Alt + ? > FAQ</span></p>\n            <p><strong>Problème de solde client ?</strong> Le solde est recalculé à partir des bons. Vérifiez les doublons de facturation.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">❓ 9.1 الأسئلة الشائعة وحل المشاكل</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">القائمة الرئيسية > Alt + ? > الأسئلة الشائعة</span></p>\n            <p><strong>مشكلة في رصيد الزبون؟</strong> يعاد حساب الرصيد تلقائيًا من الفواتير، تأكد من عدم تكرار تسجيل فلوكة البيع.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><small>Dépannage: Actualisez la page (Ctrl+F5)</small></div>\n          </div>', '9-2': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>💬 9.2 Questions & Réponses</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Menu Principal > Alt + ? > Q&A</span></p>\n            <p><strong>Q : Le logiciel fonctionne-t-il hors-ligne ?</strong> R : Oui ! L\'hébergement est local, seule l\'IA en ligne requiert internet.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">💬 9.2 أسئلة وأجوبة</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">القائمة الرئيسية > Alt + ? > أسئلة وأجوبة</span></p>\n            <p><strong>س: هل يعمل البرنامج بدون اتصال؟</strong> ج: نعم، قواعد البيانات والبرنامج مخزنة محليًا على حاسوبك.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><small>Q: Hors-ligne? | R: Oui (100% Local)</small></div>\n          </div>', '9-3': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>⌨️ 9.3 Raccourcis Clavier</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Raccourcis globaux actifs à l\'écran</span></p>\n            <p>Alt+S (Nouvelle Vente), Alt+P (Règlement Client), Alt+C (Contacts), Alt+? (Ouvrir ce manuel).</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">⌨️ 9.3 اختصارات لوحة المفاتيح</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الاختصارات النشطة في جميع الواجهات</span></p>\n            <p>Alt+S (بيع جديد)، Alt+P (دفعة جديدة)، Alt+C (جهات الاتصال)، Alt+? (فتح الدليل).</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><kbd>Alt</kbd> + <kbd>?</kbd> = Manuel / الدليل</div>\n          </div>', '9-4': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📞 9.4 Support & Versions</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Menu Principal > Alt + ? > Support</span></p>\n            <p>Pour toute assistance technique, contactez le support de FABOuanes. Version actuelle : v3.1.2.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📞 9.4 الدعم الفني والإصدارات</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">القائمة الرئيسية > Alt + ? > الدعم الفني</span></p>\n            <p>للحصول على الدعم الفني والتقني يرجى الاتصال بنا. نسخة البرنامج الحالية: v3.1.2.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">Version: <span class="badge bg-success">v3.1.2</span></div>\n          </div>', '9-5': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📱 9.5 Démarrage Rapide Mobile</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Smartphone connecté > Navigateur mobile</span></p>\n            <p>Après appairage, utilisez l\'interface simplifiée de votre téléphone pour ajouter rapidement des ventes et scanner les articles.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📱 9.5 دليل الهاتف السريع</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">الهاتف المقترن > متصفح الهاتف</span></p>\n            <p>بعد الاقتران، استخدم واجهة هاتفك البسيطة لتسجيل المبيعات السريعة ومسح السلع مباشرة بالهاتف.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center"><i class="bi bi-phone" style="font-size:1.5rem;"></i><br><small>Mobile Sync OK</small></div>\n          </div>', '9-6': '<!-- French Content -->\n          <div class="lang-fr">\n            <h3>📖 9.6 Lexique des termes</h3>\n            <p><strong>Chemin d\'accès :</strong> <span class="badge bg-secondary">Menu Principal > Alt + ? > Lexique</span></p>\n            <p><strong>PAMP :</strong> Prix d\'Achat Moyen Pondéré. <strong>Créance :</strong> Dette en cours du client. <strong>Solde :</strong> Différence cumulée.</p>\n          </div>\n          \n          <!-- Arabic Content -->\n          <div class="lang-ar" dir="rtl" style="display:none; text-align: right;">\n            <h3 style="border-bottom: 2px solid var(--system-blue, #2563eb); padding-bottom: 6px; font-family: \'Outfit\', sans-serif;">📖 9.6 قاموس المصطلحات</h3>\n            <p><strong>مسار الوصول :</strong> <span class="badge bg-secondary">القائمة الرئيسية > Alt + ? > المصطلحات</span></p>\n            <p><strong>PAMP:</strong> متوسط سعر الشراء. <strong>الديون:</strong> المبالغ المتبقية بذمة العميل. <strong>الرصيد:</strong> الناتج الحسابي التراكمي.</p>\n          </div>\n          \n          <!-- Interactive Widget (rendered in both languages) -->\n          <div class="widget-wrapper my-3">\n            <div class="border rounded p-2 bg-light text-center">PAMP = Total Achats / Quantité</div>\n          </div>'}
